&quot;: line += 1 self.peek_next() continue else: break # 判断从现在开始的子字符串是不是一个block # 判断方法：需要有完整的&#123;&#125;，而且还得考虑嵌套block的可能 def is_block(self): curr_idx = self.idx jde = False self.skip_blank() # 一开始就得是一个&#123;&#125;包裹的字符串 if self.peek != &quot;&#123;&quot;: jde = False balance = 1 self.peek_next() while self.idx &lt; self.len: if self.peek == &quot;&#123;&quot;: balance += 1 elif self.peek == &quot;&#125;&quot;: balance -= 1 self.peek_next() if balance == 0: jde = True self.idx = curr_idx self.peek = self.input[self.idx] return jde &quot;&quot;&quot; block -&gt; &#x27;&#123;&#x27; decls stmts &#x27;&#125;&#x27; 这里我也考虑了空白符 &quot;&quot;&quot; def block(self): self.skip_blank() if self._match(&quot;&#123;&quot;) == False: return False # self.saved = self.top self.top = Env(self.top) self.print(&quot;&#123; &quot;) self.skip_blank() self.decls() # decls和stmts可以是空串，所以这里就不判断了 self.stmts() self.skip_blank() if self._match(&quot;&#125;&quot;) == False: return False # self.top = self.saved self.top = self.top.prev self.print(&quot;&#125; &quot;) return True # decls -&gt; decls decl | ε # !TODO: 这玩意像是左递归的，能写出来嘛？ # 尝试转换成右递归： # delcs -&gt; decl decls | ε def decls(self): self.skip_blank() self.save() if self.decl() == False: # 对应的ε空串，作为返回条件 self.load() return self.decls() def decl(self): self.skip_blank() # 啥也没有 if self.peek in [&quot;&#123;&quot;, &quot;&#125;&quot;]: return False # self.type() # type是终结子，就不再单独搞个函数了,不然不好实现语义动作 lab = self.label() if lab == &quot;&quot;: return False if lab in [&quot;int&quot;, &quot;char&quot;, &quot;bool&quot;, &quot;float&quot;, &quot;double&quot;]: s = Symbol(lab) else: # raise &quot;error syntax: no *type* found&quot; return False self.skip_blank() # self.id() lab = self.label() if lab == &quot;&quot;: return False if lab not in [&quot;int&quot;, &quot;char&quot;, &quot;bool&quot; &quot;float&quot;, &quot;double&quot;]: self.top.put(lab, s) else: # raise &quot;error syntax: id&quot; return False self.skip_blank() if self._match(&quot;;&quo