epth) except TypeError as msg: print(&quot;Sorry:&quot;, msg, file=file) print(file=file) # __code__对象 elif hasattr(x, &#x27;co_code&#x27;): # Code object _disassemble_recursive(x, file=file, depth=depth) # 字节码对象 elif isinstance(x, (bytes, bytearray)): # Raw bytecode _disassemble_bytes(x, file=file) # 源码字符串 elif isinstance(x, str): # Source code _disassemble_str(x, file=file, depth=depth) else: raise TypeError(&quot;don&#x27;t know how to disassemble %s objects&quot; % type(x).__name__) def _disassemble_recursive(co, *, file=None, depth=None): disassemble(co, file=file) # __code__ if depth is None or depth &gt; 0: if depth is not None: depth = depth - 1 for x in co.co_consts: if hasattr(x, &#x27;co_code&#x27;): print(file=file) print(&quot;Disassembly of %r:&quot; % (x,), file=file) _disassemble_recursive(x, file=file, depth=depth) def disassemble(co, lasti=-1, *, file=None): &quot;&quot;&quot;Disassemble a code object.&quot;&quot;&quot; cell_names = co.co_cellvars + co.co_freevars linestarts = dict(findlinestarts(co)) # 还是调用到这个，解码co_code _disassemble_bytes(co.co_code, lasti, co.co_varnames, co.co_names, co.co_consts, cell_names, linestarts, file=file) def _disassemble_bytes(code, lasti=-1, varnames=None, names=None, constants=None, cells=None, linestarts=None, *, file=None, line_offset=0): # Omit the line number column entirely if we have no line number info show_lineno = bool(linestarts) if show_lineno: maxlineno = max(linestarts.values()) + line_offset if maxlineno &gt;= 1000: lineno_width = len(str(maxlineno)) else: lineno_width = 3 else: lineno_width = 0 maxoffset = len(code) - 2 if maxoffset &gt;= 10000: offset_width = len(str(maxoffset)) else: offset_width = 4 # _get_instructions_bytes遍历字节码，返回元组 for instr in _get_instructions_bytes(code, varnames, names, constants, cells, linestarts, line_offset=line_offset): new_source_line = (show_lineno and instr.starts_line is not None and instr.offset &gt; 0) if new_source_line: print(file=file) is_current_instr = instr.offset == lasti print(instr._disassemble(lineno_width, is_current_instr, offset_width), file=file)# 用yield生成一个Instruction()对象的生成器# 核心逻辑def _get_instructions_bytes(code, varnames=None, names=None, constants=None, cells=None, linestarts=None, line_offset=0): &quot;&quot;&quot;Iterate over the instructions in a bytecode string. Generates a sequence of Instruction namedtuples giving the details of each opcode. Additional information about the code&#x27;s runtime environment (e.g. variable names, constants) can be specified using optional arguments. &quot;&quot;&quot; labels = findlabels(code) starts_line = None for offset, op, arg in _unpack_opargs(code): if linestarts is not None: starts_line = linestarts.get(offset, None) if starts_line is not None: starts_line += line_offset is_jump_target = offset in labels argval = None argrepr = &#x27;&#x27; if arg is not None: # Set argval to the dereferenced value of the argument when # available, and argrepr to the string representation of argval. # _disassemble_bytes needs the string repr of the # raw name index for LOAD_GLOBAL, LOAD_CONST, etc. argval = arg if op in hasconst: argval, argrepr = _get_const_info(arg, constants) elif op in hasname: argval, argrepr = _get_name_info(arg, names) elif op in hasjabs: argval = arg*2 argrepr = &quot;to &quot; + repr(argval) elif op in hasjrel: argval = offset + 2 + arg*2 argrepr = &quot;to &quot; + repr(argval) elif op in haslocal: argval, argrepr = _get_name_info(arg, varnames) elif op in hascompare: argval = cmp_op[arg] argrepr = argval elif op in hasfree: argval, argrepr = _get_name_info(arg, cells) elif op == FORMAT_VALUE: argval, argrepr = FORMAT_VALUE_CONVERTERS[arg &amp; 0x3] argval = (argval, bool(arg &amp; 0x4)) if argval[1]: if argrepr: argrepr += &#x27;, &#x27; argrepr += &#x27;with format&#x27; elif op == MAKE_FUNCTION: argrepr = &#x27;, &#x27;.join(s for i, s in enumerate(MAKE_FUNCTION_FLAGS) if arg &amp; (1&lt;&lt;i)) yield Instruction(opname[op], op, arg, argval, argrepr, offset, starts_line, is_jump_target)# 这个主要是格式化打印class Instruction(): # ... def _disassemble(self, lineno_width=3, mark_as_current=False, offset_width=4): &quot;&quot;&quot;Format instruction details for inclusion in disassembly output *lineno_width* sets the width of the line number field (0 omits it) *mark_as_current* inserts a &#x27;--&gt;&#x27; marker arrow as part of the line *offset_width* sets the width of the instruction offset field &quot;&quot;&quot; fields = [] # Column: Source code line number if lineno_width: if self.starts_line is not None: lineno_fmt = &quot;%%%dd&quot; % lineno_width fields.append(lineno_fmt % self.starts_line) else: fields.append(&#x27; &#x27; * lineno_width) # Column: Current instruction indicator if mark_as_current: fields.append(&#x27;--&gt;&#x27;) else: fields.append(&#x27; &#x27;) # Column: Jump target marker if self.is_jump_target: fields.append(&#x27;&gt;&gt;&#x27;) else: fields.append(&#x27; &#x27;) # Column: Instruction offset from start of code sequence fields.append(repr(self.offset).rjust(offset_width)) # Column: Opcode name fields.append(self.opname.ljust(_OPNAME_WIDTH)) # Column: Opcode argument if self.arg is not None: fields.append(repr(self.arg).rjust(_OPARG_WIDTH)) # Column: Opcode argument details if self.argrepr: fields.append(&#x27;(&#x27; + self.argrepr + &#x27;)&#x27;) return &#x27; &#x27;.join(fields).rstrip() Py源码混淆源码混淆常用于解释性语言脚本中。 见到的混淆器pyminifier http://pyob.oxyry.com/ Python Source Obfuscation using ASTs | Development &amp; Security (jbremer.org) 这篇文章讲的大概是如何基于AST树来进行混淆。涉及到编译原理知识，比较高级。 混淆前（举例）12345678910111213141516171819202122232425262728293031323334353637383940414243444546class SampleClass: def __init__(self): self.data = None def method1SampleClass(self, arg): self.data = argdef function_with_if(arg): if arg == True: pass else: passdef function_with_if1(arg=True): if arg == True: print(&#x27;True&#x27;) else: print(&#x27;False&#x27;)def function_with_if2(): if True: print(&#x27;True&#x27;) else: print(&